/**
 * ORDER BY over factorized plans (Phase 5): when every order key lives in the flat prefix, the engine must sort flat
 * rows and expand branches lazily — engaging the new strategies — while producing a row stream that (a) is the same
 * multiset as the generic evaluator's and (b) is correctly ordered by the query's keys. Rows tied on the order keys may
 * legally appear in any order (SPARQL leaves ties unspecified), so exact list comparison is only used where the data
 * makes the ordering total.
 */
public class LmdbNativeOrderedFactorizedTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			IRI p5 = vf.createIRI(EX, "p5");
			conn.begin();
			// 40 subjects in blocks of four per hub; each hub fans out to 6 mids; each mid has three p3
			// targets (multi-value expansion) and exactly one p5 target (total order for window tests)
			for (int i = 0; i < 40; i++) {
				conn.add(vf.createIRI(EX, String.format("s%02d", i)), p1, vf.createIRI(EX, "hub" + (i / 4)));
			}
			for (int h = 0; h < 10; h++) {
				IRI hub = vf.createIRI(EX, "hub" + h);
				for (int m = 0; m < 6; m++) {
					IRI mid = vf.createIRI(EX, "mid" + h + "_" + m);
					conn.add(hub, p2, mid);
					for (int t = 0; t < 3; t++) {
						conn.add(mid, p3, vf.createIRI(EX, "t" + h + "_" + m + "_" + t));
					}
					conn.add(mid, p5, vf.createIRI(EX, "w" + h + "_" + m));
				}
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void fullSortSortsFlatRowsAndExpandsLazily() {
		// ?y is flat whichever pattern roots the plan (it feeds the p3 probe); ?s and ?z are enum-branch
		// fresh. Rows tied on ?y are branch expansions: any order among them is legal.
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y ?z WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } ORDER BY ?y";
		long sortsBefore = NativeRowsStep.ORDERED_FACTORIZED_SORTS.get();

		assertSameRowsAndSortedBy(query, "y");

		assertThat(NativeRowsStep.ORDERED_FACTORIZED_SORTS.get())
				.as("flat-prefix order keys should engage the factorized full sort")
				.isGreaterThan(sortsBefore);
	}

	@Test
	public void topKKeepsBoundedHeapOfFlatRows() {
		// each ?y ties exactly four rows (four subjects per hub, one p5 target per mid); the window's
		// offset and limit are multiples of four, so it contains whole tie groups and the row multiset
		// is deterministic even though tie order is not
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y ?w WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p5 ?w } ORDER BY ?y"
				+ " OFFSET 4 LIMIT 24";
		long topKBefore = NativeRowsStep.ORDERED_FACTORIZED_TOPK.get();

		assertSameRowsAndSortedBy(query, "y");

		assertThat(NativeRowsStep.ORDERED_FACTORIZED_TOPK.get())
				.as("ORDER BY + LIMIT over a factorized plan should keep a bounded heap of flat rows")
				.isGreaterThan(topKBefore);
	}

	@Test
	public void countBranchMultiplicityExpandsInSortedOrder() {
		// ?z unprojected: p3 degrades to a COUNT branch; each row repeats per its match count
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } ORDER BY ?y";
		long sortsBefore = NativeRowsStep.ORDERED_FACTORIZED_SORTS.get();

		assertSameRowsAndSortedBy(query, "y");

		assertThat(NativeRowsStep.ORDERED_FACTORIZED_SORTS.get())
				.as("COUNT-branch multiplicity should ride the flat sort")
				.isGreaterThan(sortsBefore);
	}

	@Test
	public void branchOrderKeyFallsBackToClassicSort() {
		// ?z is bound by the enum branch: sorting flat rows cannot honor it, the gate must refuse.
		// (?z ?y ?s) totally orders the rows, so exact list equality holds on the classic path.
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y ?z WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } ORDER BY ?z ?y ?s";
		long sortsBefore = NativeRowsStep.ORDERED_FACTORIZED_SORTS.get();
		long topKBefore = NativeRowsStep.ORDERED_FACTORIZED_TOPK.get();

		assertSameOrderAsGeneric(query);

		assertThat(NativeRowsStep.ORDERED_FACTORIZED_SORTS.get()).isEqualTo(sortsBefore);
		assertThat(NativeRowsStep.ORDERED_FACTORIZED_TOPK.get()).isEqualTo(topKBefore);
	}

	@Test
	public void distinctFallsBackToClassicSort() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT DISTINCT ?s ?y WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } ORDER BY ?y ?s";
		long sortsBefore = NativeRowsStep.ORDERED_FACTORIZED_SORTS.get();
		long topKBefore = NativeRowsStep.ORDERED_FACTORIZED_TOPK.get();

		assertSameOrderAsGeneric(query);

		assertThat(NativeRowsStep.ORDERED_FACTORIZED_SORTS.get()).isEqualTo(sortsBefore);
		assertThat(NativeRowsStep.ORDERED_FACTORIZED_TOPK.get()).isEqualTo(topKBefore);
	}

	@Test
	public void flagOffFallsBackToClassicSort() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?y ?z WHERE { ?s ex:p1 ?x . ?x ex:p2 ?y . ?y ex:p3 ?z } ORDER BY ?y";
		String previous = System.getProperty("rdf4j.lmdb.orderedFactorizedRows.enabled");
		System.setProperty("rdf4j.lmdb.orderedFactorizedRows.enabled", "false");
		long sortsBefore = NativeRowsStep.ORDERED_FACTORIZED_SORTS.get();
		try {
			assertSameRowsAndSortedBy(query, "y");
			assertThat(NativeRowsStep.ORDERED_FACTORIZED_SORTS.get()).isEqualTo(sortsBefore);
		} finally {
			if (previous == null) {
				System.clearProperty("rdf4j.lmdb.orderedFactorizedRows.enabled");
			} else {
				System.setProperty("rdf4j.lmdb.orderedFactorizedRows.enabled", previous);
			}
		}
	}

	/** Exact list comparison — only sound when the order keys totally order the rows (or ties are identical). */
	private void assertSameOrderAsGeneric(String query) {
		List<String> nativeRows = rows(repository, query);
		List<String> genericRows = genericRows(query);
		assertThat(nativeRows)
				.as("native vs generic (ordered) for:\n" + query)
				.containsExactlyElementsOf(genericRows);
	}

	/**
	 * Tie-safe comparison: the same multiset of rows, and the key columns non-decreasing in emission order (the
	 * fixture's IRI local names are fixed-width, so lexicographic string order equals SPARQL IRI order).
	 */
	private void assertSameRowsAndSortedBy(String query, String... keyNames) {
		List<BindingSet> nativeRows = bindingSets(repository, query);
		List<String> nativeCanonical = canonicalize(nativeRows);
		List<String> genericRows = genericRows(query);
		assertThat(nativeCanonical)
				.as("native vs generic (multiset) for:\n" + query)
				.containsExactlyInAnyOrderElementsOf(genericRows);
		String previousKey = null;
		for (BindingSet row : nativeRows) {
			StringBuilder key = new StringBuilder();
			for (String name : keyNames) {
				key.append(row.getValue(name).stringValue()).append(' ');
			}
			if (previousKey != null) {
				assertThat(key.toString())
						.as("order keys must be non-decreasing for:\n" + query)
						.isGreaterThanOrEqualTo(previousKey);
			}
			previousKey = key.toString();
		}
	}

	private List<String> genericRows(String query) {
		String previous = System.getProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
		try {
			System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", "false");
			return rows(repository, query);
		} finally {
			if (previous == null) {
				System.clearProperty("rdf4j.lmdb.nativeQueryEngine.enabled");
			} else {
				System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", previous);
			}
		}
	}

	private static List<BindingSet> bindingSets(SailRepository repo, String query) {
		try (SailRepositoryConnection conn = repo.getConnection()) {
			return QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
		}
	}

	private static List<String> canonicalize(List<BindingSet> rows) {
		return rows.stream()
				.map(bs -> bs.getBindingNames()
						.stream()
						.sorted()
						.map(name -> name + "=" + bs.getValue(name))
						.collect(Collectors.joining(";")))
				.collect(Collectors.toList());
	}

	private static List<String> rows(SailRepository repo, String query) {
		return canonicalize(bindingSets(repo, query));
	}
}
